class Solution:
    def countKConstraintSubstrings(self, s, k):
        n = len(s)
        total = 0
        for i in range(n):
            for j in range(i, n):
                sub = s[i:j + 1]
                if sub.count('0') <= k or sub.count('1') <= k:
                    total += 1
        return total

