var countKConstraintSubstrings = function(s, k) {
    const n = s.length;
    let count = 0;
    for (let i = 0; i < n; i++) {
        let zeros = 0, ones = 0;
        for (let j = i; j < n; j++) {
            if (s[j] === '0') zeros++; else ones++;
            if (zeros <= k || ones <= k) count++;
        }
    }
    return count;
};
